// isPK reports whether `col` is part of the schema's primary key list.
func isPK(sc datatable.Schema, col string) bool {
	for _, k := range sc.PrimaryKey {
		if k == col {
			return true
		}
	}
	return false
}

// pkVal extracts the row's PK as a single string (joined when composite).
func pkVal(sc datatable.Schema, row map[string]any) string {
	parts := make([]string, 0, len(sc.PrimaryKey))
	for _, k := range sc.PrimaryKey {
		parts = append(parts, fmt.Sprintf("%v", row[k]))
	}
	return strings.Join(parts, "|")
}

// hasUserCols reports whether the schema has any non-system columns.
func hasUserCols(sc datatable.Schema) bool {
	for _, c := range sc.Columns {
		if !c.System {
			return true
		}
	}
	return false
}

// boolStr returns "true" / "false" for use in data-* attributes.
func boolStr(b bool) string {
	if b {
		return "true"
	}
	return "false"
}

func formatCell(v any) string {
	if v == nil {
		return ""
	}
	return fmt.Sprintf("%v", v)
}

// formatSize returns "0.01MB" / "0MB" — n8n-style.
func formatSize(b int64) string {
	if b <= 0 {
		return "0MB"
	}
	mb := float64(b) / 1024.0 / 1024.0
	if mb < 0.01 {
		return "0.01MB"
	}
	return fmt.Sprintf("%.2fMB", mb)
}

// relTime renders a coarse "N units ago" label. Empty time = "—".
func relTimeDT(t time.Time) string {
	if t.IsZero() {
		return "—"
	}
	d := time.Since(t)
	switch {
	case d < time.Minute:
		return "just now"
	case d < time.Hour:
		return fmt.Sprintf("%d minutes ago", int(d.Minutes()))
	case d < 24*time.Hour:
		return fmt.Sprintf("%d hours ago", int(d.Hours()))
	case d < 30*24*time.Hour:
		return fmt.Sprintf("%d days ago", int(d.Hours()/24))
	case d < 365*24*time.Hour:
		return fmt.Sprintf("%d months ago", int(d.Hours()/(24*30)))
	}
	return fmt.Sprintf("%d years ago", int(d.Hours()/(24*365)))
}

